use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer};
use std::fs;
use std::path::{Path, PathBuf};

const UPLOADS_DIR: &str = "/uploads";

fn get_file(req: HttpRequest) -> Result<HttpResponse, HttpResponse> {
    let filename = req.match_info().get("filename").unwrap_or("");
    let base_dir = Path::new(UPLOADS_DIR);
    let path = base_dir.join(filename);

    if !path.is_absolute() && !filename.contains("..") {
        let file_contents = fs::read_to_string(path).map_err(|_| HttpResponse::NotFound())?;
        Ok(HttpResponse::Ok().body(file_contents))
    } else {
        Err(HttpResponse::Forbidden().finish())
    }
}

fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route(&format!("/uploads/{filename:.*}", filename = r"[^/]+"), web::get(get_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
}